+        let server = ServerBuilder::new("srv", "1.0")
+            .on_duplicate(DuplicateBehavior::Error)
+            .resource(DupResource("dup"))
+            .resource(DupResource("dup"))
+            .build();
+        assert!(server.has_resources());
+    }
